import * as fs from 'fs';
import * as path from 'path';
import { fileURLToPath } from 'url';
import { AcousticEngine } from '../../aether/src/acoustic-siphon';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

/**
 * Acoustic Amplituhedron Builder
 * 
 * This script processes the entire range of 39 ARPAbet phonemes to build 
 * the permanent L1 Isolate Cache for the Vacuum Architecture.
 * 
 * Pipeline:
 * 1. SYNTH: Condense the mathematical "Platonic Ideal" of the phoneme.
 * 2. DILATE: Takens' Delay Embedding of the audio into phase space.
 * 3. SIEVE: Persistent Homology approximation of beta_1 holes.
 * 4. FOLD: Extract metrics and project into a 196,884-D Moonshine Vector.
 * 5. PUBLISH: Save to the Amplituhedron cache.
 */

async function buildCache() {
  console.log('============================================================');
  console.log(' Building Acoustic Amplituhedron — Persistent L1 Cache');
  console.log('============================================================\n');

  const engine = new AcousticEngine();
  const cache: Record<string, any> = {};

  const projectRoot = path.resolve(__dirname, '../../..');
  const geometriesPath = path.join(projectRoot, 'open-source/aether/src/phoneme-geometries.json');
  const phonemes = JSON.parse(fs.readFileSync(geometriesPath, 'utf8'));

  for (const spec of phonemes) {
    // Determine the baseline trace using the core formants
    const trace = Math.floor(spec.f1 + spec.f2 + spec.f3) % 1000000;
    
    console.log(`[SYNTH] Condensing pure geometry for: ${spec.id} (Trace: ${trace})`);
    
    // 1. Synthesize the "Platonic Ideal" audio
    const audio = await engine.condense({
      expectedCoordinate: 1,
      expectedBoundaryTrace: trace,
      timestamp_gravity: 0
    });

    if (audio.length === 0) {
      console.warn(`    -> Warning: Empty audio for ${spec.id}`);
      continue;
    }

    // 2 & 3 & 4. Pass through Vietoris-Rips / Takens Filtration to get the true barcode
    console.log(`[SIEVE] Siphoning topological signature...`);
    const vector = await engine.siphon(audio);
    
    // Overwrite the ID with the semantic phoneme label
    vector.nodeId = `phoneme_${spec.id}`;
    
    cache[spec.id] = vector;
    console.log(`    -> Beta1: ${Math.floor(vector.boundaryTrace / 1000)}, Dilation: ${vector.bulkState[0].toFixed(2)}, Density: ${vector.bulkState[1].toFixed(2)}`);
  }

  const outputPath = path.join(projectRoot, 'open-source/aether/src/amplituhedron-cache.json');
  fs.writeFileSync(outputPath, JSON.stringify(cache, null, 2));

  console.log(`Successfully built L1 Acoustic Cache with ${Object.keys(cache).length} Moonshine Vectors.`);
  console.log(`Saved to: ${outputPath}`);
}

buildCache().catch(console.error);